import React, { useState } from "react";
import "bootstrap/dist/css/bootstrap.min.css";

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);

  return (
    <div className="container py-5">

      <div className="row justify-content-center">
        <div className="col-md-6">

          <div className="card shadow p-4">

            <h3 className="text-center mb-4">
              {isLogin ? "تسجيل الدخول" : "إنشاء حساب"}
            </h3>

            {!isLogin && (
              <input className="form-control mb-3" placeholder="الاسم الكامل" />
            )}

            <input className="form-control mb-3" placeholder="الإيميل" />
            <input className="form-control mb-3" placeholder="كلمة المرور" type="password" />

            {!isLogin && (
              <input className="form-control mb-3" placeholder="تأكيد كلمة المرور" type="password" />
            )}

            <button className="btn btn-primary w-100 mb-3">
              {isLogin ? "تسجيل الدخول" : "إنشاء حساب"}
            </button>

            <p className="text-center">
              {isLogin ? "ما عندك حساب؟" : "عندك حساب؟"}
              <span
                className="text-primary ms-2"
                style={{ cursor: "pointer" }}
                onClick={() => setIsLogin(!isLogin)}
              >
                {isLogin ? "سجل الآن" : "سجل دخول"}
              </span>
            </p>

          </div>
        </div>
      </div>

    </div>
  );
};

export default AuthPage;
